629: // findNodesThatPassFilters finds the nodes that fit the filter plugins.
630: func (sched *Scheduler) findNodesThatPassFilters(
631: 	ctx context.Context,
632: 	schedFramework framework.Framework,
633: 	state fwk.CycleState,
634: 	pod *v1.Pod,
635: 	diagnosis *framework.Diagnosis,
636: 	nodes []fwk.NodeInfo) ([]fwk.NodeInfo, error) {
637: 	numAllNodes := len(nodes)
638: 	numNodesToFind := sched.numFeasibleNodesToFind(schedFramework.PercentageOfNodesToScore(), int32(numAllNodes))
639: 	if !sched.hasExtenderFilters() && !sched.hasScoring(schedFramework) {
640: 		numNodesToFind = 1
641: 	}
642: 
643: 	// Create feasible list with enough space to avoid growing it
644: 	// and allow assigning.
645: 	feasibleNodes := make([]fwk.NodeInfo, numNodesToFind)
646: 
647: 	if !schedFramework.HasFilterPlugins() {
648: 		for i := range feasibleNodes {
649: 			feasibleNodes[i] = nodes[(sched.nextStartNodeIndex+i)%numAllNodes]
650: 		}
651: 		return feasibleNodes, nil
652: 	}
653: 
654: 	errCh := parallelize.NewResultChannel[error]()
655: 	var feasibleNodesLen int32
656: 	ctx, cancel := context.WithCancelCause(ctx)
657: 	defer cancel(errors.New("findNodesThatPassFilters has completed"))
658: 
659: 	type nodeStatus struct {
660: 		node   string
661: 		status *fwk.Status
662: 	}
663: 	result := make([]*nodeStatus, numAllNodes)
664: 	checkNode := func(i int) {
665: 		// We check the nodes starting from where we left off in the previous scheduling cycle,
666: 		// this is to make sure all nodes have the same chance of being examined across pods.
667: 		nodeInfo := nodes[(sched.nextStartNodeIndex+i)%numAllNodes]
668: 		status := schedFramework.RunFilterPluginsWithNominatedPods(ctx, state, pod, nodeInfo)
669: 		if status.Code() == fwk.Error {
670: 			errCh.SendWithCancel(status.AsError(), func() {
671: 				cancel(errors.New("some other Filter operation failed"))
672: 			})
673: 			return
674: 		}
675: 		if status.IsSuccess() {
676: 			length := atomic.AddInt32(&feasibleNodesLen, 1)
677: 			if length > numNodesToFind {
678: 				cancel(errors.New("findNodesThatPassFilters has found enough nodes"))
679: 				atomic.AddInt32(&feasibleNodesLen, -1)
680: 			} else {
681: 				feasibleNodes[length-1] = nodeInfo
682: 			}
683: 		} else {
684: 			result[i] = &nodeStatus{node: nodeInfo.Node().Name, status: status}
685: 		}
686: 	}
687: 
688: 	beginCheckNode := time.Now()
689: 	statusCode := fwk.Success
690: 	defer func() {
691: 		// We record Filter extension point latency here instead of in framework.go because framework.RunFilterPlugins
692: 		// function is called for each node, whereas we want to have an overall latency for all nodes per scheduling cycle.
693: 		// Note that this latency also includes latency for `addNominatedPods`, which calls framework.RunPreFilterAddPod.
694: 		metrics.FrameworkExtensionPointDuration.WithLabelValues(metrics.Filter, statusCode.String(), schedFramework.ProfileName()).Observe(metrics.SinceInSeconds(beginCheckNode))
695: 	}()
696: 
697: 	// Stops searching for more nodes once the configured number of feasible nodes
698: 	// are found.
699: 	schedFramework.Parallelizer().Until(ctx, numAllNodes, checkNode, metrics.Filter)
700: 	feasibleNodes = feasibleNodes[:feasibleNodesLen]
701: 	for _, item := range result {
702: 		if item == nil {
703: 			continue
704: 		}
705: 		diagnosis.NodeToStatus.Set(item.node, item.status)
706: 		diagnosis.AddPluginStatus(item.status)
707: 	}
708: 	if err := errCh.Receive(); err != nil {
709: 		statusCode = fwk.Error
710: 		return feasibleNodes, err
711: 	}
712: 	return feasibleNodes, nil
713: }
